# Terraform: S3 Access Point with all Block Public Access settings enabled
resource "aws_s3_access_point" "<example_resource_name>" {
  name   = "<example_resource_name>"
  bucket = "<example_bucket_name>"

  public_access_block_configuration {
    block_public_acls       = true  # Critical: block public ACLs
    ignore_public_acls      = true  # Critical: ignore any public ACLs
    block_public_policy     = true  # Critical: block public policies
    restrict_public_buckets = true  # Critical: restrict public buckets
  }
}

# Enable bucket-level Public Access Block so public bucket policies (including write) are blocked
resource "aws_s3_bucket_public_access_block" "<example_resource_name>" {
  bucket                   = "<example_resource_id>"
  restrict_public_buckets  = true  # Critical: prevents public access granted via bucket policies
}

# Enable minimal S3 Block Public Access on the bucket
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = "<example_resource_name>"

  ignore_public_acls     = true  # Critical: ignores public ACLs
  restrict_public_buckets = true # Critical: restricts buckets with public policies
}

# Block public listing by enabling bucket-level Public Access Block
resource "aws_s3_bucket_public_access_block" "<example_resource_name>" {
  bucket                 = "<example_resource_id>"
  ignore_public_acls     = true  # Critical: ignore any public ACLs
  restrict_public_buckets = true # Critical: restrict buckets with public policies
}

# Ensure the bucket is not publicly writable via ACLs
resource "aws_s3_bucket_public_access_block" "<example_resource_name>" {
  bucket                  = "<example_resource_name>"
  ignore_public_acls      = true  # Critical: disables effect of public ACLs (e.g., AllUsers/AuthenticatedUsers)
  restrict_public_buckets = true  # Critical: restricts public buckets to the account to prevent public writes
}

# Terraform: Enable required S3 Account-level Block Public Access settings
resource "aws_s3_account_public_access_block" "<example_resource_name>" {
  ignore_public_acls     = true  # Critical: Ignores any public ACLs account-wide
  restrict_public_buckets = true # Critical: Restricts buckets with public policies to same-account principals
}

# Terraform: restrict bucket policy to this AWS account only
resource "aws_s3_bucket_policy" "<example_resource_name>" {
  bucket = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Principal = { AWS = "arn:aws:iam::<example_resource_id>:root" } # Critical: limits access to the bucket owner's account, preventing cross-account access
      Action    = "s3:*"
      Resource  = [
        "arn:aws:s3:::<example_resource_name>",
        "arn:aws:s3:::<example_resource_name>/*"
      ]
    }]
  })
}

# Enable required S3 Block Public Access settings on a bucket
resource "aws_s3_bucket_public_access_block" "<example_resource_name>" {
  bucket                   = "<example_resource_id>"
  ignore_public_acls       = true  # CRITICAL: Ignore public ACLs
  restrict_public_buckets  = true  # CRITICAL: Restrict public buckets
}

# Terraform: pre-claim the predictable S3 bucket name to ensure your account owns it
resource "aws_s3_bucket" "<example_resource_name>" {
  bucket = "<FLAGGED_BUCKET_NAME>"  # Critical: create the exact bucket name reported by the check so it is owned by this account
}

# Terraform: MRAP with Block Public Access enabled (must be set at creation)
resource "aws_s3control_multi_region_access_point" "<example_resource_name>" {
  account_id = "<example_account_id>"

  details {
    name = "<example_resource_name>"

    public_access_block {                 # Critical: enable all Block Public Access settings
      block_public_acls       = true      # Critical
      ignore_public_acls      = true      # Critical
      block_public_policy     = true      # Critical
      restrict_public_buckets = true      # Critical
    }

    region { bucket = "<example_bucket_name_1>" }
    region { bucket = "<example_bucket_name_2>" }
  }
}

# Disable ACLs by enforcing bucket owner for all objects
resource "aws_s3_bucket_ownership_controls" "<example_resource_name>" {
  bucket = "<example_resource_id>"
  rule {
    object_ownership = "BucketOwnerEnforced" # Critical: Disables ACLs and enforces bucket owner
  }
}

resource "aws_s3_bucket" "<example_resource_name>" {
  bucket = "<example_resource_name>"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "<example_resource_name>" {
  bucket = aws_s3_bucket.<example_resource_name>.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"  # Critical: enables default SSE-S3 for the bucket
    }
  }
}

# Enable default SSE-KMS on an existing S3 bucket
resource "aws_s3_bucket_server_side_encryption_configuration" "<example_resource_name>" {
  bucket = "<example_bucket_name>"

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms" # Critical: enforces SSE-KMS by default
    }
  }
}

# Enable versioning on an existing S3 bucket
resource "aws_s3_bucket_versioning" "<example_resource_name>" {
  bucket = "<example_resource_name>"
  versioning_configuration {
    status = "Enabled"  # Critical: enables bucket versioning to remediate the finding
  }
}

remediation.console_steps:
1. In the AWS Console, go to S3 and open the bucket <example_resource_name>
2. Select the Permissions tab and click Edit in Bucket policy
3. Paste this policy, replacing the bucket name:
   ```
   {
     "Version": "2012-10-17",
     "Statement": [
       {
         "Effect": "Deny",
         "Principal": "*",
         "Action": "s3:*",
         "Resource": "arn:aws:s3:::<example_resource_name>/*",
         "Condition": { "Bool": { "aws:SecureTransport": "false" } }
       }
     ]
   }
   ```
4. Click Save changes

